class Solution {
public:
    int longestDecomposition(string text) {
        int n = text.size();
        int res = 1;
        for (int i = 1; i <= n / 2; ++i) {
            if (text.substr(0, i) == text.substr(n - i)) {
                res = max(res, 2 + longestDecomposition(text.substr(i, n - 2 * i)));
            }
        }
        return res;
    }
};
```
